package com.azhar.noor_e_islam.data.remote.api

import com.squareup.moshi.JsonClass
import retrofit2.http.GET
import retrofit2.http.Path

/* --- Quran (alquran.cloud) --- */
interface QuranApi {
    @GET("surah")
    suspend fun listSurahs(): SurahListResponse

    @GET("surah/{number}/{edition}")
    suspend fun surahWithEdition(
        @Path("number") number: Int,
        @Path("edition") edition: String = "quran-uthmani"
    ): SurahDetailResponse
}

@JsonClass(generateAdapter = true)
data class SurahListResponse(val code: Int, val status: String, val data: List<SurahDto>)

@JsonClass(generateAdapter = true)
data class SurahDto(
    val number: Int,
    val name: String,
    val englishName: String,
    val englishNameTranslation: String,
    val numberOfAyahs: Int,
    val revelationType: String,
)

@JsonClass(generateAdapter = true)
data class SurahDetailResponse(val code: Int, val status: String, val data: SurahDetailDto)

@JsonClass(generateAdapter = true)
data class SurahDetailDto(
    val number: Int,
    val name: String,
    val englishName: String,
    val ayahs: List<AyahDto>,
)

@JsonClass(generateAdapter = true)
data class AyahDto(
    val number: Int,
    val text: String,
    val numberInSurah: Int,
    val juz: Int,
    val audio: String? = null,
)

/* --- Aladhan calendar / prayer times --- */
interface HijriApi {
    @GET("gToH")
    suspend fun gregorianToHijri(): HijriDateResponse
}

@JsonClass(generateAdapter = true)
data class HijriDateResponse(val code: Int, val data: HijriDataDto)

@JsonClass(generateAdapter = true)
data class HijriDataDto(val hijri: HijriDto)

@JsonClass(generateAdapter = true)
data class HijriDto(
    val day: String,
    val month: HijriMonthDto,
    val year: String,
)

@JsonClass(generateAdapter = true)
data class HijriMonthDto(val number: Int, val en: String, val ar: String)

package com.azhar.noor_e_islam.data.remote.api

import com.squareup.moshi.JsonClass
import retrofit2.http.GET
import retrofit2.http.Path

/* --- Quran (alquran.cloud) ---
 * Bulk endpoint: https://api.alquran.cloud/v1/quran/{edition}
 * Returns the entire Quran for a single edition in one response.
 * Edition examples:
 *   "ar.alafasy"   → Arabic uthmani text + Mishary Alafasy audio per ayah
 *   "en.sahih"     → English (Saheeh International) translation, no audio
 *   "ur.junagarhi" → Urdu translation, no audio
 */
interface QuranApi {
    /** Bulk fetch — entire Quran for the given edition. */
    @GET("quran/{edition}")
    suspend fun fullQuran(
        @Path("edition") edition: String
    ): QuranBulkResponse
}

@JsonClass(generateAdapter = true)
data class QuranBulkResponse(
    val code: Int,
    val status: String,
    val data: QuranBulkData,
)

@JsonClass(generateAdapter = true)
data class QuranBulkData(
    val surahs: List<BulkSurahDto>,
    val edition: EditionDto,
)

@JsonClass(generateAdapter = true)
data class BulkSurahDto(
    val number: Int,
    val name: String,
    val englishName: String,
    val englishNameTranslation: String,
    val revelationType: String, // "Meccan" | "Medinan"
    val ayahs: List<BulkAyahDto>,
)

@JsonClass(generateAdapter = true)
data class BulkAyahDto(
    val number: Int,
    val text: String,
    val numberInSurah: Int,
    val juz: Int = 1,
    val audio: String? = null,
    val audioSecondary: List<String>? = null,
)

@JsonClass(generateAdapter = true)
data class EditionDto(
    val identifier: String,
    val language: String,
    val name: String,
    val englishName: String,
    val format: String,
    val type: String,
)

/* --- Aladhan calendar / prayer times --- */
interface HijriApi {
    @GET("gToH")
    suspend fun gregorianToHijri(): HijriDateResponse
}

@JsonClass(generateAdapter = true)
data class HijriDateResponse(val code: Int, val data: HijriDataDto)

@JsonClass(generateAdapter = true)
data class HijriDataDto(val hijri: HijriDto)

@JsonClass(generateAdapter = true)
data class HijriDto(
    val day: String,
    val month: HijriMonthDto,
    val year: String,
)

@JsonClass(generateAdapter = true)
data class HijriMonthDto(val number: Int, val en: String, val ar: String)

package com.azhar.noor_e_islam.core.util

import android.os.Build
import android.icu.util.IslamicCalendar
import java.util.Calendar
import java.util.GregorianCalendar
import java.util.TimeZone

/**
 * Hijri ↔ Gregorian conversion using ICU's [IslamicCalendar] (Umm al-Qura
 * civil arithmetic), available on API 24+ which matches our minSdk.
 *
 * All math is fully offline.
 */
object HijriCalendarUtil {

    /** Convert a Hijri (year/month/day, month is 1..12) to a Gregorian [Calendar]. */
    fun hijriToGregorian(hijriYear: Int, hijriMonth1Based: Int, hijriDay: Int): Calendar? {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.N) return null
        val islamic = IslamicCalendar(TimeZone.getDefault()).apply {
            set(IslamicCalendar.ERA, 1)
            set(IslamicCalendar.YEAR, hijriYear)
            set(IslamicCalendar.MONTH, hijriMonth1Based - 1) // ICU is 0-based
            set(IslamicCalendar.DAY_OF_MONTH, hijriDay)
        }
        val millis = islamic.timeInMillis
        return GregorianCalendar(TimeZone.getDefault()).apply { timeInMillis = millis }
    }

    /** Get the Hijri year(s) that overlap a given Gregorian year. */
    fun hijriYearsInGregorianYear(gregorianYear: Int): List<Int> {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.N) return emptyList()
        val years = mutableSetOf<Int>()
        // Sample Jan 1 and Dec 31 of the Gregorian year, plus mid-year.
        listOf(0, 5, 11).forEach { monthIdx ->
            val day = if (monthIdx == 11) 31 else 1
            val cal = GregorianCalendar(gregorianYear, monthIdx, day)
            val islamic = IslamicCalendar(TimeZone.getDefault()).apply {
                timeInMillis = cal.timeInMillis
            }
            years += islamic.get(IslamicCalendar.YEAR)
        }
        return years.sorted()
    }
}

package com.azhar.noor_e_islam.core.util

import android.icu.util.IslamicCalendar
import android.icu.util.ULocale
import java.util.Calendar
import java.util.GregorianCalendar
import java.util.TimeZone

/**
 * Hijri ↔ Gregorian conversion using ICU's [IslamicCalendar] (Umm al-Qura
 * civil arithmetic), available on API 24+ which matches our minSdk.
 *
 * All math is fully offline.
 */
object HijriCalendarUtil {

    private fun newIslamic(): IslamicCalendar {
        // Use ULocale-based ctor with a TimeZone set explicitly afterwards
        // to avoid ambiguity with java.util.TimeZone.
        val cal = IslamicCalendar(ULocale.getDefault())
        cal.timeZone = android.icu.util.TimeZone.getDefault()
        return cal
    }

    /** Convert a Hijri (year/month/day, month is 1..12) to a Gregorian [Calendar]. */
    fun hijriToGregorian(hijriYear: Int, hijriMonth1Based: Int, hijriDay: Int): Calendar? {
        val islamic = newIslamic()
        islamic.clear()
        islamic.set(IslamicCalendar.ERA, 1)
        islamic.set(IslamicCalendar.YEAR, hijriYear)
        islamic.set(IslamicCalendar.MONTH, hijriMonth1Based - 1) // ICU is 0-based
        islamic.set(IslamicCalendar.DAY_OF_MONTH, hijriDay)
        val millis = islamic.timeInMillis
        return GregorianCalendar(TimeZone.getDefault()).apply { timeInMillis = millis }
    }

    /** Get the Hijri year(s) that overlap a given Gregorian year. */
    fun hijriYearsInGregorianYear(gregorianYear: Int): List<Int> {
        val years = mutableSetOf<Int>()
        // Sample Jan 1, mid-year, and Dec 31 to cover all overlapping Hijri years.
        listOf(0 to 1, 5 to 1, 11 to 31).forEach { (monthIdx, day) ->
            val cal = GregorianCalendar(gregorianYear, monthIdx, day)
            val islamic = newIslamic()
            islamic.timeInMillis = cal.timeInMillis
            years.add(islamic.get(IslamicCalendar.YEAR))
        }
        return years.sorted()
    }
}

