import com.azhar.noor_e_islam.R
import com.azhar.noor_e_islam.core.ui.components.AyahCard
import com.azhar.noor_e_islam.core.ui.components.GeometricPatternBg
import com.azhar.noor_e_islam.core.ui.components.IslamicCard
import com.azhar.noor_e_islam.core.ui.components.SectionHeader
import com.azhar.noor_e_islam.ui.theme.Gold500
import com.azhar.noor_e_islam.ui.theme.NoorGradients

private data class QuickItem(val labelRes: Int, val icon: ImageVector, val onClick: () -> Unit)

@Composable
fun HomeScreen(
    onOpenSurah: (Int) -> Unit,
    onOpenQuran: () -> Unit,
    onOpenCalendar: () -> Unit,
    onOpenDua: () -> Unit,
    onOpenStories: () -> Unit,
    onOpenLearn: () -> Unit,
    viewModel: HomeViewModel = hiltViewModel(),
) {
    val state by viewModel.state.collectAsState()

    Column(
        modifier = Modifier
            .fillMaxSize()
            .verticalScroll(rememberScrollState())
            .padding(bottom = 88.dp)
    ) {
        // Sync banner — visible while the Quran corpus is being downloaded for the first time.
        if (state.isQuranSyncing) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(MaterialTheme.colorScheme.primaryContainer)
                    .padding(horizontal = 16.dp, vertical = 10.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                CircularProgressIndicator(
                    modifier = Modifier.size(18.dp),
                    strokeWidth = 2.dp,
                    color = MaterialTheme.colorScheme.primary,
                )
                Spacer(Modifier.width(12.dp))
                Text(
                    text = "Downloading Quran… first-time sync",
                    style = MaterialTheme.typography.labelLarge,
                    color = MaterialTheme.colorScheme.onPrimaryContainer
                )
            }
        } else if (state.quranSyncError != null) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(MaterialTheme.colorScheme.errorContainer)
                    .padding(horizontal = 16.dp, vertical = 10.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    text = "Quran sync failed: ${state.quranSyncError}",
                    style = MaterialTheme.typography.labelLarge,
                    color = MaterialTheme.colorScheme.onErrorContainer
                )
            }
        }

        // Hero header
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .height(200.dp)
                .background(NoorGradients.Emerald)
        ) {
            GeometricPatternBg(modifier = Modifier.fillMaxSize())
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(20.dp),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.Top
            ) {
                Column {
                    Text(stringResource(R.string.greeting_assalam), color = Gold500, style = MaterialTheme.typography.titleMedium)
                    Text(state.userName, color = Color.White, style = MaterialTheme.typography.headlineMedium, fontWeight = FontWeight.SemiBold)
                    Spacer(Modifier.height(8.dp))
                    Text(state.gregorian, color = Color.White.copy(alpha = 0.85f), style = MaterialTheme.typography.bodyMedium)
                    if (state.hijri.isNotBlank())
                        Text(state.hijri, color = Color.White.copy(alpha = 0.7f), style = MaterialTheme.typography.bodySmall)
                }
                IconButton(onClick = { /* notifications */ }) {
                    Icon(Icons.Outlined.Notifications, contentDescription = "Notifications", tint = Color.White)
                }
            }
        }

        // Today's highlights
        SectionHeader(title = stringResource(R.string.todays_hadith))
        AyahCard(
            arabic = "اَلْمُؤْمِنُ لِلْمُؤْمِنِ كَالْبُنْيَانِ يَشُدُّ بَعْضُهُ بَعْضًا",
            translation = "A believer to another believer is like a building whose parts support each other.",
            reference = "Sahih al-Bukhari 481",
            modifier = Modifier.padding(horizontal = 16.dp).fillMaxWidth()
        )

        Spacer(Modifier.height(8.dp))

        // Quick access grid
        SectionHeader(title = stringResource(R.string.quick_access))
        val items = listOf(
            QuickItem(R.string.quran,    Icons.Filled.MenuBook,      onOpenQuran),
            QuickItem(R.string.dua,      Icons.Filled.Favorite,      onOpenDua),
            QuickItem(R.string.calendar, Icons.Filled.CalendarMonth, onOpenCalendar),
            QuickItem(R.string.stories,  Icons.Filled.AutoStories,   onOpenStories),
            QuickItem(R.string.learn_islam, Icons.Filled.School,     onOpenLearn),
        )
        LazyVerticalGrid(
            columns = GridCells.Fixed(3),
            modifier = Modifier.fillMaxWidth().padding(horizontal = 12.dp).height(220.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp),
            horizontalArrangement = Arrangement.spacedBy(8.dp),
            userScrollEnabled = false,
        ) {
            items(items) { item ->
                IslamicCard(modifier = Modifier.fillMaxWidth(), onClick = item.onClick) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally, modifier = Modifier.fillMaxWidth()) {
                        Icon(item.icon, contentDescription = null, tint = MaterialTheme.colorScheme.primary)
                        Spacer(Modifier.height(8.dp))
                        Text(stringResource(item.labelRes), style = MaterialTheme.typography.labelLarge)
                    }
                }
            }
        }

        // Continue reading
        SectionHeader(title = stringResource(R.string.continue_reading))
        IslamicCard(
            modifier = Modifier.padding(horizontal = 16.dp).fillMaxWidth(),
            onClick = { onOpenSurah(state.lastReadSurah) }
        ) {
            Text("Surah ${state.lastReadSurah}, Ayah ${state.lastReadAyah}", style = MaterialTheme.typography.titleMedium)
            Spacer(Modifier.height(6.dp))
            LinearProgressIndicator(progress = { 0.35f }, modifier = Modifier.fillMaxWidth())
        }
        Spacer(Modifier.height(16.dp))
    }
}

package com.azhar.noor_e_islam.presentation.home

import androidx.compose.foundation.background
import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.*
