private data class QuickItem(val label: String, val icon: ImageVector, val onClick: () -> Unit)
private data class HighlightItem(val tag: String, val text: String, val ref: String)

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun HomeScreen(
    onOpenSurah: (Int) -> Unit,
    onOpenQuran: () -> Unit,
    onOpenCalendar: () -> Unit,
    onOpenDua: () -> Unit,
    onOpenStories: () -> Unit,
    onOpenLearn: () -> Unit,
    onOpenMenu: () -> Unit = {},
    onOpenHadith: () -> Unit = {},
    viewModel: HomeViewModel = hiltViewModel(),
) {
    val state by viewModel.state.collectAsState()

    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(MaterialTheme.colorScheme.background)
            .verticalScroll(rememberScrollState())
            .padding(bottom = 88.dp)
    ) {
        // Top bar
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 16.dp, vertical = 12.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            IconButton(onClick = onOpenMenu) {
                Icon(Icons.Outlined.Menu, contentDescription = "Menu", tint = Emerald900)
            }
            Spacer(Modifier.width(4.dp))
            Column(modifier = Modifier.weight(1f)) {
                Text(
                    "As-salamu Alaikum",
                    style = MaterialTheme.typography.titleLarge,
                    color = Emerald900,
                    fontWeight = FontWeight.Bold
                )
                Text(
                    "May Allah bless your day",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }
            IconButton(onClick = { /* notifications */ }) {
                Icon(Icons.Outlined.Notifications, null, tint = Emerald900)
            }
        }

        // Sync banner
        if (state.isQuranSyncing) {
            SyncBanner(text = "Downloading Quran… first-time sync")
        } else if (state.quranSyncError != null) {
            SyncBanner(text = "Quran sync failed: ${state.quranSyncError}", isError = true)
        }

        // Today's Date card
        IslamicCard(
            modifier = Modifier
                .padding(horizontal = 16.dp)
                .fillMaxWidth(),
        ) {
            Text(
                "Today's Date",
                style = MaterialTheme.typography.labelMedium,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )
            Spacer(Modifier.height(6.dp))
            Text(
                state.hijri.ifBlank { "Loading…" },
                style = MaterialTheme.typography.titleMedium,
                color = Emerald900,
                fontWeight = FontWeight.SemiBold
            )
            Text(
                state.gregorian,
                style = MaterialTheme.typography.bodyMedium,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )
        }

        Spacer(Modifier.height(20.dp))

        // Today's Highlights
        SectionTitle("Today's Highlights", showArrow = true)
        Spacer(Modifier.height(8.dp))
        val highlights = listOf(
            HighlightItem("Hadith",     "Never belittle a good deed.",            "Sahih Muslim 2626"),
            HighlightItem("Importance", "The day of Dhul-Qi'dah is a virtuous day.", "Tafsir Ibn Kathir"),
            HighlightItem("Incident",   "The Treaty of Hudaybiyyah",              "6 AH"),
        )
        LazyRow(
            contentPadding = PaddingValues(horizontal = 16.dp),
            horizontalArrangement = Arrangement.spacedBy(12.dp),
            modifier = Modifier.fillMaxWidth()
        ) {
            items(highlights.size) { idx ->
                HighlightCard(highlights[idx], onClick = if (idx == 0) onOpenHadith else { -> {} })
            }
        }

        Spacer(Modifier.height(20.dp))

        // Quick Access — 5 icons row
        SectionTitle("Quick Access")
        Spacer(Modifier.height(10.dp))
        val quickItems = listOf(
            QuickItem("Quran",    Icons.AutoMirrored.Filled.MenuBook, onOpenQuran),
            QuickItem("Hadith",   Icons.Filled.FormatQuote,           onOpenHadith),
            QuickItem("Calendar", Icons.Filled.CalendarMonth,         onOpenCalendar),
            QuickItem("Dua",      Icons.Filled.Favorite,              onOpenDua),
            QuickItem("Stories",  Icons.Filled.AutoStories,           onOpenStories),
        )
        Row(
            modifier = Modifier.fillMaxWidth().padding(horizontal = 12.dp),
            horizontalArrangement = Arrangement.SpaceEvenly
        ) {
            quickItems.forEach { QuickAccessIcon(it) }
        }

        Spacer(Modifier.height(20.dp))

        // Continue Reading
        SectionTitle("Continue Reading")
        Spacer(Modifier.height(8.dp))
        IslamicCard(
            modifier = Modifier.padding(horizontal = 16.dp).fillMaxWidth(),
            onClick = { onOpenSurah(state.lastReadSurah) }
        ) {
            Row(verticalAlignment = Alignment.CenterVertically) {
                Box(
                    modifier = Modifier
                        .size(40.dp)
                        .clip(RoundedCornerShape(10.dp))
                        .background(Emerald900),
                    contentAlignment = Alignment.Center
                ) {
                    Icon(
                        Icons.AutoMirrored.Filled.MenuBook,
                        null,
                        tint = Gold500,
                        modifier = Modifier.size(20.dp)
                    )
                }
                Spacer(Modifier.width(12.dp))
                Column(modifier = Modifier.weight(1f)) {
                    Text(
                        "Surah Al-Baqarah",
                        style = MaterialTheme.typography.titleMedium,
                        fontWeight = FontWeight.SemiBold,
                        color = MaterialTheme.colorScheme.onSurface
                    )
                    Text(
                        "Page 12 | Ayah ${state.lastReadAyah}",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(20.dp))
                        .background(Gold500.copy(alpha = 0.18f))
                        .padding(horizontal = 16.dp, vertical = 6.dp)
                ) {
                    Text(
                        "View",
                        style = MaterialTheme.typography.labelLarge,
                        color = Gold500,
                        fontWeight = FontWeight.SemiBold
                    )
                }
            }
        }
        Spacer(Modifier.height(16.dp))
    }
}

@Composable
private fun SectionTitle(text: String, showArrow: Boolean = false) {
    Row(
        modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Text(
            text,
            style = MaterialTheme.typography.titleMedium,
            color = Emerald900,
            fontWeight = FontWeight.Bold,
            modifier = Modifier.weight(1f)
        )
        if (showArrow) {
            Text("›", color = Emerald900, fontSize = 22.sp, fontWeight = FontWeight.Bold)
        }
    }
}

@Composable
private fun HighlightCard(item: HighlightItem, onClick: () -> Unit) {
    IslamicCard(
        modifier = Modifier.width(180.dp),
        onClick = onClick
    ) {
        Text(
            item.tag,
            style = MaterialTheme.typography.labelMedium,
            color = Gold500,
            fontWeight = FontWeight.SemiBold
        )
        Spacer(Modifier.height(8.dp))
        Text(
            item.text,
            style = MaterialTheme.typography.bodyMedium,
            color = Emerald900,
            fontWeight = FontWeight.Medium,
            maxLines = 3
        )
        Spacer(Modifier.height(10.dp))
        Text(
            item.ref,
            style = MaterialTheme.typography.labelSmall,
            color = MaterialTheme.colorScheme.onSurfaceVariant
        )
    }
}

@Composable
private fun QuickAccessIcon(item: QuickItem) {
    Column(
        horizontalAlignment = Alignment.CenterHorizontally,
        modifier = Modifier
            .clip(RoundedCornerShape(12.dp))
            .clickableNoRipple(item.onClick)
            .padding(8.dp)
    ) {
        Box(
            modifier = Modifier
                .size(56.dp)
                .clip(CircleShape)
                .background(Gold500.copy(alpha = 0.16f)),
            contentAlignment = Alignment.Center
        ) {
            Icon(item.icon, null, tint = Emerald900, modifier = Modifier.size(26.dp))
        }
        Spacer(Modifier.height(6.dp))
        Text(
            item.label,
            style = MaterialTheme.typography.labelMedium,
            color = Emerald900,
            fontWeight = FontWeight.Medium
        )
    }
}

@Composable
private fun SyncBanner(text: String, isError: Boolean = false) {
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp, vertical = 6.dp)
            .clip(RoundedCornerShape(10.dp))
            .background(
                if (isError) MaterialTheme.colorScheme.errorContainer
                else MaterialTheme.colorScheme.primaryContainer
            )
            .padding(horizontal = 12.dp, vertical = 8.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        if (!isError) {
            CircularProgressIndicator(
                modifier = Modifier.size(16.dp),
                strokeWidth = 2.dp,
                color = MaterialTheme.colorScheme.primary
            )
            Spacer(Modifier.width(10.dp))
        }
        Text(
            text,
            style = MaterialTheme.typography.labelMedium,
            color = if (isError) MaterialTheme.colorScheme.onErrorContainer
                    else MaterialTheme.colorScheme.onPrimaryContainer
        )
    }
}

@Composable
private fun Modifier.clickableNoRipple(onClick: () -> Unit): Modifier =
    this.then(Modifier.clip(RoundedCornerShape(12.dp))).then(
        androidx.compose.foundation.clickable(
            interactionSource = androidx.compose.runtime.remember {
                androidx.compose.foundation.interaction.MutableInteractionSource()
            },
            indication = androidx.compose.material.ripple.rememberRipple(bounded = false, radius = 36.dp),
            onClick = onClick
        )
    )

// LazyRow.items helper — provides indexed iteration without bringing in foundation.lazy.items
private fun androidx.compose.foundation.lazy.LazyListScope.items(
    count: Int,
    block: @Composable (Int) -> Unit
) = items(count = count, key = null) { index -> block(index) }

package com.azhar.noor_e_islam.presentation.quran.reader

import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.azhar.noor_e_islam.core.audio.AyahAudioPlayer
import com.azhar.noor_e_islam.core.util.Resource
import com.azhar.noor_e_islam.domain.model.Ayah
import com.azhar.noor_e_islam.domain.model.Bookmark
import com.azhar.noor_e_islam.domain.model.BookmarkType
import com.azhar.noor_e_islam.domain.repository.BookmarkRepository
import com.azhar.noor_e_islam.domain.usecase.GetAyahsUseCase
import com.azhar.noor_e_islam.domain.usecase.UpdateLastReadUseCase
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import javax.inject.Inject

data class QuranReaderState(
    val surahId: Int = 1,
    val isLoading: Boolean = true,
    val ayahs: List<Ayah> = emptyList(),
    val error: String? = null,
)

@HiltViewModel
class QuranReaderViewModel @Inject constructor(
    handle: SavedStateHandle,
    getAyahs: GetAyahsUseCase,
    private val updateLastRead: UpdateLastReadUseCase,
    private val bookmarkRepo: BookmarkRepository,
    val audio: AyahAudioPlayer,
) : ViewModel() {
    private val _state = MutableStateFlow(QuranReaderState(surahId = handle.get<Int>("surahId") ?: 1))
    val state: StateFlow<QuranReaderState> = _state

    /** Set of bookmarked refIds, exposed as flow so UI can highlight. */
    val bookmarkedRefs: StateFlow<Set<String>> = bookmarkRepo.observeAll()
        .map { list -> list.filter { it.type == BookmarkType.AYAH }.map { it.refId }.toSet() }
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5_000), emptySet())

    val currentAudioUrl get() = audio.currentUrl
    val isAudioPlaying  get() = audio.isPlaying

    init {
        val surah = _state.value.surahId
        viewModelScope.launch {
            getAyahs(surah).collect { res ->
                _state.update {
                    when (res) {
                        is Resource.Loading -> it.copy(isLoading = true)
                        is Resource.Success -> it.copy(isLoading = false, ayahs = res.data, error = null)
                        is Resource.Error   -> it.copy(isLoading = false, error = res.message)
                    }
                }
            }
        }
    }

    fun togglePlay(ayah: Ayah) {
        val url = ayah.audioUrl ?: return
        audio.toggle(url)
    }

    fun toggleBookmark(ayah: Ayah) = viewModelScope.launch {
        val refId = "${ayah.surahNumber}:${ayah.number}"
        val existing = bookmarkRepo.observeAll().map { list -> list.firstOrNull { it.refId == refId && it.type == BookmarkType.AYAH } }
        // Inline check by reading current set
        if (bookmarkedRefs.value.contains(refId)) {
            // Find the bookmark id from cloud-of-truth (Room) by reading the latest list.
            // Cheap path: store id == refId for ayah bookmarks.
            bookmarkRepo.remove(refId)
        } else {
            bookmarkRepo.add(
                Bookmark(
                    id = refId,
                    type = BookmarkType.AYAH,
                    refId = refId,
                    title = "Surah ${ayah.surahNumber}, Ayah ${ayah.number}",
                    subtitle = ayah.translation.take(80),
                )
            )
        }
    }

    fun markRead(ayah: Int) = viewModelScope.launch {
        updateLastRead(_state.value.surahId, ayah)
    }

    override fun onCleared() {
        audio.stop()
        super.onCleared()
    }
}

